import{_ as e,o as n,c as o,a3 as l}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"37. Lead Apron Allowance","description":"","frontmatter":{"title":"37. Lead Apron Allowance","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","shift-work","allowances","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/allowances/37-lead-apron-allowance.md","filePath":"ebas/has-managers-admin/common-terms/allowances/37-lead-apron-allowance.md"}'),r={name:"ebas/has-managers-admin/common-terms/allowances/37-lead-apron-allowance.md"};function s(t,a,i,c,d,p){return n(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="_37-lead-apron-allowance" tabindex="-1">37. Lead Apron Allowance <a class="header-anchor" href="#_37-lead-apron-allowance" aria-label="Permalink to &quot;37. Lead Apron Allowance&quot;">​</a></h1><p><strong>37.1</strong> From the FFPPOA 13 May 2021, an Employee who is required as part of their usual duties to wear a lead apron, is to be paid the Lead Apron Allowance in <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedules 2C</a> and 3C (Allowances) for each shift or part thereof on which the lead apron is worn. Classifications entitled to this allowance are:</p><p><strong>(a)</strong> Theatre Technicians (including Liver Transplant Technologists and Dual Qualified Technicians); and</p><p><strong>(b)</strong> Interpreters and Theatre Technician Managers.</p><p>Plain language terms: radiation allowance, x-ray allowance.</p>',5)])])}const w=e(r,[["render",s]]);export{m as __pageData,w as default};
